previewCss:
.darma-loader-uiverse-aqua-pill-fill {
  /* color of choise */
  --clr: #05A8AA;
  /* loading time of choice */
  --load-time: 2s;
  outline: 5px solid var(--clr);
  outline-offset: 5px;
  position: relative;
  overflow: hidden;
  border-radius: 5rem;
  /* width: 10rem; */
  /* height: 2rem; */
  padding: 1rem 5rem;
  /* use either padding or width + height*/
  /* I prefer the padding one */
  /* rotate: -90deg; */
  /* rotate if you want/need vertical loader */
}

.darma-loader-uiverse-aqua-pill-fill::after {
content: '';
position: absolute;
top: 0;
left: 0;
width: 100%;
height: 100%;
background-color: var(--clr);
z-index: 2;
animation: darma-loader-uiverse-aqua-pill-fill-loading var(--load-time) ease-in-out infinite;
}

@keyframes darma-loader-uiverse-aqua-pill-fill-loading {
0% {
width: 0%;
}

100% {
width: 100%;
}
}

.darma-loader-darma-custom-226 {
  width: 90px;
  height: 14px;
  color: var(--loader-color, #4f46e5);
  background: 
    linear-gradient(90deg,currentColor 50%,#0000 0) repeat-x,
    conic-gradient(from 45deg at right 7px top  50%,currentColor 90deg,#0000 0);
  background-position: calc(100%/3) 50%;
  background-size:calc(100%/4) 60%,calc(100%/4) 100%;
  animation: darma-loader-darma-custom-226-l7 0.5s infinite linear;
}
@keyframes darma-loader-darma-custom-226-l7 {
    100% {background-position: 0 50%}
}

.darma-loader-darma-custom-041 {
  width: 80px;
  height: 40px;
  color: #000;
  border: 2px solid currentColor;
  border-right-color: transparent;
  padding: 3px;
  background:
    repeating-linear-gradient(90deg, currentColor 0 10px, #0000 0 15px)
    0/0% no-repeat content-box content-box;
  position: relative;
  box-sizing: border-box;
  animation: darma-loader-darma-custom-041-l5 2s infinite steps(6);
}
.darma-loader-darma-custom-041::before {
  content: "";
  position: absolute;
  top: -2px;
  bottom: -2px;
  left: 100%;
  width: 10px;
  background:
    linear-gradient(#0000 calc(50% - 7px), currentColor 0 calc(50% - 5px), #0000 0 calc(50% + 5px), currentColor 0 calc(50% + 7px), #0000 0) left/100% 100%,
    linear-gradient(currentColor calc(50% - 5px), #0000 0 calc(50% + 5px), currentColor 0) left/2px 100%,
    linear-gradient(#0000 calc(50% - 5px), currentColor 0 calc(50% + 5px), #0000 0) right/2px 100%;
  background-repeat: no-repeat;
}
@keyframes darma-loader-darma-custom-041-l5 {
  100% { background-size: 120%; }
}

.darma-loader-darma-custom-023 {
  width: 120px;
  height: 22px;
  border-radius: 40px;
  color: var(--loader-color, #514b82);
  border: 2px solid;
  position: relative;
}
.darma-loader-darma-custom-023::before {
  content: "";
  position: absolute;
  margin: 2px;
  width: 25%;
  top: 0;
  bottom: 0;
  left: 0;
  border-radius: inherit;
  background: currentColor;
  animation: darma-loader-darma-custom-023-l3 1s infinite linear;
}
@keyframes darma-loader-darma-custom-023-l3 {
  50% { left: 100%; transform: translateX(calc(-100% - 4px)); }
}

.darma-loader-uiverse-candy-stripe-progress {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-direction: column;
  gap: 5px;
}

.darma-loader-uiverse-candy-stripe-progress__loading-text {
color: white;
font-size: 14pt;
font-weight: 600;
margin-left: 10px;
}

.darma-loader-uiverse-candy-stripe-progress__dot {
margin-left: 3px;
animation: darma-loader-uiverse-candy-stripe-progress-blink 1.5s infinite;
}
.darma-loader-uiverse-candy-stripe-progress__dot:nth-child(2) {
animation-delay: 0.3s;
}

.darma-loader-uiverse-candy-stripe-progress__dot:nth-child(3) {
animation-delay: 0.6s;
}

.darma-loader-uiverse-candy-stripe-progress__loading-bar-background {
--height: 30px;
display: flex;
align-items: center;
box-sizing: border-box;
padding: 5px;
width: 200px;
height: var(--height);
background-color: #212121 /*change this*/;
box-shadow: #0c0c0c -2px 2px 4px 0px inset;
border-radius: calc(var(--height) / 2);
}

.darma-loader-uiverse-candy-stripe-progress__loading-bar {
position: relative;
display: flex;
justify-content: center;
flex-direction: column;
--height: 20px;
width: 0%;
height: var(--height);
overflow: hidden;
background: rgb(222, 74, 15);
background: linear-gradient(
0deg,
rgba(222, 74, 15, 1) 0%,
rgba(249, 199, 79, 1) 100%
);
border-radius: calc(var(--height) / 2);
animation: darma-loader-uiverse-candy-stripe-progress-loading 4s ease-out infinite;
}

.darma-loader-uiverse-candy-stripe-progress__white-bars-container {
position: absolute;
display: flex;
align-items: center;
gap: 18px;
}

.darma-loader-uiverse-candy-stripe-progress__white-bar {
background: rgb(255, 255, 255);
background: linear-gradient(
-45deg,
rgba(255, 255, 255, 1) 0%,
rgba(255, 255, 255, 0) 70%
);
width: 10px;
height: 45px;
opacity: 0.3;
rotate: 45deg;
}

@keyframes darma-loader-uiverse-candy-stripe-progress-loading {
0% {
width: 0;
}
80% {
width: 100%;
}
100% {
width: 100%;
}
}

@keyframes darma-loader-uiverse-candy-stripe-progress-blink {
0%,
100% {
opacity: 0;
}
50% {
opacity: 1;
}
}

