.darma-loader-darma-custom-660 {--loader-bg: var(--loader-bg, #0f172a);

  --cloud-color: var(--loader-color, #4387f4);
  --arrows-color: var(--loader-secondary-color, #80b1ff);
  --time-animation: 1s;
  transform: scale(1); /* You can change the size */
}

.darma-loader-darma-custom-660 #darma-loader-darma-custom-660-cloud {
  width: 100px;
  height: 100px;
}

.darma-loader-darma-custom-660 #darma-loader-darma-custom-660-cloud rect {
  fill: var(--cloud-color);
}

.darma-loader-darma-custom-660 #darma-loader-darma-custom-660-cloud g:nth-child(3) {
  transform-origin: 50% 72.8938%;
  fill: var(--arrows-color);
  filter: drop-shadow(0 0 8px color-mix(in srgb, var(--loader-color, var(--loader-color, #4387f4)) 60%, transparent));
  animation: darma-loader-darma-custom-660-rotation var(--time-animation) linear infinite;
}

.darma-loader-darma-custom-660 #darma-loader-darma-custom-660-shapes g g circle {
  animation: darma-loader-darma-custom-660-cloud calc(var(--time-animation) * 2) linear infinite;
}

.darma-loader-darma-custom-660 #darma-loader-darma-custom-660-shapes g g circle:nth-child(2) {
  animation-delay: calc((var(--time-animation) * 2) / -3);
}

.darma-loader-darma-custom-660 #darma-loader-darma-custom-660-shapes g g circle:nth-child(3) {
  animation-delay: calc((var(--time-animation) * 2) / -1.5);
}

.darma-loader-darma-custom-660 svg #darma-loader-darma-custom-660-lines g line {
  stroke-width: 5;
  transform-origin: 50% 50%;
  rotate: -65deg;
  animation: darma-loader-darma-custom-660-lines calc(var(--time-animation) / 1.33) linear infinite;
}

@keyframes darma-loader-darma-custom-660-rotation {
  0% {
    transform: rotate(0deg);
  }
  50% {
    transform: rotate(180deg);
  }
  100% {
    transform: rotate(360deg);
  }
}

@keyframes darma-loader-darma-custom-660-lines {
  0% {
    transform: translateY(-10px);
  }
  100% {
    transform: translateY(8px);
  }
}

@keyframes darma-loader-darma-custom-660-cloud {
  0% {
    cx: 20;
    cy: 60;
    r: 15;
  }
  50% {
    cx: 50;
    cy: 45;
    r: 20;
  }
  100% {
    cx: 80;
    cy: 60;
    r: 15;
  }
}

.darma-loader-darma-custom-047 {
  width: 60px;
  aspect-ratio: 1;
  border-radius: 50%;
  animation: darma-loader-darma-custom-047-l11 2s infinite;
}
@keyframes darma-loader-darma-custom-047-l11 {
  0% { background: conic-gradient(var(--loader-color, #f03355) 0, #0000 0); }
  12.5% { background: conic-gradient(var(--loader-color, #f03355) 45deg, #0000 46deg); }
